// Extract customer data and message details
const events = $input.first().json.events || [];
if (events.length === 0) {
  return { error: 'No events found' };
}

const event = events[0];
const userId = event.source?.userId || 'unknown';
const messageText = event.message?.text || '';
const messageId = event.message?.id || Date.now().toString();
const timestamp = new Date(event.timestamp || Date.now()).toISOString();

// Check if message has image
const hasImage = event.message?.type === 'image';
const imageId = hasImage ? event.message.id : null;

// Extract issue details using simple text processing
function extractCategory(text) {
  const lowerText = text.toLowerCase();
  if (lowerText.includes('bug') || lowerText.includes('error') || lowerText.includes('ผิดพลาด')) return 'bug';
  if (lowerText.includes('feature') || lowerText.includes('request') || lowerText.includes('ขอ')) return 'feature';
  if (lowerText.includes('login') || lowerText.includes('password') || lowerText.includes('รหัสผ่าน')) return 'account';
  return 'general';
}

const issueData = {
  userId: userId,
  messageId: messageId,
  originalText: messageText,
  timestamp: timestamp,
  hasImage: hasImage,
  imageId: imageId,
  urgency: messageText.toLowerCase().includes('urgent') || messageText.includes('เร่งด่วน') ? 'high' : 'normal',
  category: extractCategory(messageText),
  replyToken: event.replyToken || ''
};

return issueData;

