// Simulate Gemini AI analysis
const customerData = $('Extract Customer Data').item.json;
const similarIssues = $input.first().json.result || [];

// Simple AI simulation based on keywords and patterns
function analyzeIssue(text, category, similarCount) {
  const lowerText = text.toLowerCase();

  // Determine priority
  let priority = 'Normal';
  if (lowerText.includes('urgent') || lowerText.includes('เร่งด่วน') || lowerText.includes('ด่วน')) {
    priority = 'Urgent';
  } else if (lowerText.includes('critical') || lowerText.includes('ล่ม') || lowerText.includes('ไม่ทำงาน')) {
    priority = 'High';
  } else if (lowerText.includes('minor') || lowerText.includes('เล็กน้อย')) {
    priority = 'Low';
  }

  // Determine assignee type
  let assigneeType = 'backend';
  if (lowerText.includes('ui') || lowerText.includes('design') || lowerText.includes('หน้าตา')) {
    assigneeType = 'frontend';
  } else if (lowerText.includes('server') || lowerText.includes('database') || lowerText.includes('api')) {
    assigneeType = 'backend';
  } else if (lowerText.includes('deploy') || lowerText.includes('server') || lowerText.includes('infrastructure')) {
    assigneeType = 'devops';
  } else if (lowerText.includes('test') || lowerText.includes('ทดสอบ')) {
    assigneeType = 'qa';
  }

  // Generate summary
  const summary = `${category.charAt(0).toUpperCase() + category.slice(1)} issue: ${text.substring(0, 100)}${text.length > 100 ? '...' : ''}`;

  // Generate steps
  const steps = [
    'Analyze the reported issue',
    'Reproduce the problem if possible',
    'Investigate root cause',
    'Implement fix or solution',
    'Test the resolution',
    'Update customer with resolution'
  ];

  // Estimate hours based on priority and complexity
  let estimatedHours = 4;
  if (priority === 'Urgent') estimatedHours = 2;
  if (priority === 'High') estimatedHours = 3;
  if (priority === 'Low') estimatedHours = 6;
  if (similarCount > 0) estimatedHours = Math.max(1, estimatedHours - 1); // Reduce if similar issues exist

  return {
    summary: summary,
    priority: priority,
    assignee_type: assigneeType,
    steps: steps,
    estimated_hours: estimatedHours,
    tags: [category, assigneeType]
  };
}

const analysis = analyzeIssue(
  customerData.originalText,
  customerData.category,
  similarIssues.length
);

// Format as expected by next node
return {
  text: JSON.stringify(analysis)
};

